{"content":"//! ModelMux CLI - Console Launcher
//!
//! Provides CLI commands for launching and managing ModelMux instances.

use clap::{Parser, Subcommand};
use std::process::Command;
use std::fs;
use std::path::Path;
use std::collections::HashMap;

#[derive(Parser)]
#[command(name = "modelmux")]
#[command(about = "ModelMux - Model Multiplexer and Proxy Gateway")]
#[command(long_about = None)]
struct Cli {
    #[command(subcommand)]
    command: Option<Commands>,
}

#[derive(Subcommand)]
enum Commands {
    /// Start ModelMux server
    Start {
        /// Port to bind
        #[arg(short, long, default_value = "8889")]
        port: u16,

        /// Host to bind
        #[arg(short, long, default_value = "0.0.0.0")]
        host: String,

        /// Environment file
        #[arg(short, long)]
        env: Option<String>,

        /// Log level
        #[arg(short, long, default_value = "info")]
        log: String,

        /// Run in background
        #[arg(short, long)]
        daemon: bool,

        /// Run as agent8888 on port 8888
        #[arg(long)]
        agent8888: bool,
    },

    /// Stop running ModelMux instance
    Stop,

    /// Restart ModelMux server
    Restart {
        #[arg(short, long, default_value = "8889")]
        port: u16,

        #[arg(long)]
        agent8888: bool,
    },

    /// Check if ModelMux is running
    Status,

    /// View ModelMux logs
    Logs {
        /// Number of lines
        #[arg(short, long, default_value = "50")]
        lines: usize,
    },

    /// Test ModelMux endpoints
    Test,

    /// List available models
    Models,

    /// Interactive chat with a model
    Chat {
        /// Model to use
        #[arg(short, long, default_value = "kilo_code/minimax-minimax-m2.5:free")]
        model: String,

        /// System prompt
        #[arg(short, long, default_value = "You are a helpful assistant.")]
        system: String,
    },

    /// Show current configuration
    Config,

    /// Manage environment files
    Env {
        #[command(subcommand)]
        action: EnvActions,
    },

    /// Manage model cache
    Cache {
        #[command(subcommand)]
        action: CacheActions,
    },
}

#[derive(Subcommand)]
enum EnvActions {
    /// List environment files and variables
    List,
    /// Create .env file from example
    Create,
    /// Check configured API keys
    Check,
}

#[derive(Subcommand)]
enum CacheActions {
    /// Show cache status
    Status,
    /// Clear cache
    Clear,
    /// Show cache files
    Show,
}

fn main() {
    let cli = Cli::parse();

    match &cli.command {
        Some(Commands::Start { port, host, env, log, daemon, agent8888 }) => {
            cmd_start(*port, host, env.as_deref(), log, *daemon, *agent8888);
        }
        Some(Commands::Stop) => {
            cmd_stop();
        }
        Some(Commands::Restart { port, agent8888 }) => {
            cmd_stop();
            std::thread::sleep(std::time::Duration::from_secs(1));
            cmd_start(*port, "0.0.0.0", None, "info", false, *agent8888);
        }
        Some(Commands::Status) => {
            cmd_status();
        }
        Some(Commands::Logs { lines }) => {
            cmd_logs(*lines);
        }
        Some(Commands::Test) => {
            cmd_test();
        }
        Some(Commands::Models) => {
            cmd_models();
        }
        Some(Commands::Chat { model, system }) => {
            cmd_chat(model, system);
        }
        Some(Commands::Config) => {
            cmd_config();
        }
        Some(Commands::Env { action }) => {
            cmd_env(action);
        }
        Some(Commands::Cache { action }) => {
            cmd_cache(action);
        }
        None => {
            // Default: start server
            cmd_start(8889, "0.0.0.0", None, "info", false, false);
        }
    }
}

fn cmd_start(port: u16, host: &str, env_file: Option<&str>, log_level: &str, daemon: bool, agent8888: bool) {
    println!("🚀 Starting ModelMux...");
    println!("   Host: {}", host);
    println!("   Port: {}", port);
    println!("   Log:  {}", log_level);

    // Load environment file if specified
    let env_path = env_file
        .map(|s| s.to_string())
        .or_else(|| {
            if Path::new(".env").exists() {
                Some(".env".to_string())
            } else {
                dirs::home_dir()
                    .map(|h| h.join(".modelmux/.env").to_string_lossy().to_string())
                    .filter(|p| Path::new(p).exists())
            }
        });

    if let Some(path) = &env_path {
        if let Ok(content) = fs::read_to_string(path) {
            for line in content.lines() {
                let line = line.trim();
                if line.is_empty() || line.starts_with('#') {
                    continue;
                }
                if let Some(eq) = line.find('=') {
                    let key = line[..eq].trim();
                    let value = line[eq + 1..].trim().trim_matches('"').trim_matches('\'');
                    std::env::set_var(key, value);
                }
            }
            println!("✓ Loaded environment from {}", path);
        }
    }

    // Build command
    let mut cmd = Command::new("cargo");
    cmd.arg("run").arg("--bin").arg("modelmux").arg("--");

    if agent8888 {
        cmd.arg("--agent8888");
    } else {
        cmd.arg("--port").arg(port.to_string()).arg("--serve");
    }

    cmd.env("RUST_LOG", log_level);

    if daemon {
        println!("✓ Running in background");
        // In a real implementation, you'd use proper daemonization
        match cmd.spawn() {
            Ok(child) => {
                if let Some(pid) = child.id() {
                    if let Err(e) = fs::write("modelmux.pid", pid.to_string()) {
                        eprintln!("Warning: Could not write PID file: {}", e);
                    }
                    println!("✓ ModelMux started successfully (PID: {})", pid);
                }
            }
            Err(e) => {
                eprintln!("✗ Failed to start ModelMux: {}", e);
                std::process::exit(1);
            }
        }
    } else {
        println!("✓ Starting interactive mode (Ctrl+C to stop)");
        let status = cmd.status().expect("Failed to start ModelMux");
        if !status.success() {
            std::process::exit(status.code().unwrap_or(1));
        }
    }
}

fn cmd_stop() {
    // Try PID file first
    if let Ok(pid_str) = fs::read_to_string("modelmux.pid") {
        if let Ok(pid) = pid_str.trim().parse::<u32>() {
            #[cfg(unix)]
            {
                use nix::sys::signal::{kill, Signal};
                use nix::unistd::Pid;
                if kill(Pid::from_raw(pid as i32), Signal::SIGTERM).is_ok() {
                    let _ = fs::remove_file("modelmux.pid");
                    println!("✓ ModelMux stopped (PID: {})", pid);
                    return;
                }
            }
            #[cfg(not(unix))]
            {
                Command::new("taskkill")
                    .args(["/PID", &pid.to_string(), "/F"])
                    .status()
                    .ok();
                let _ = fs::remove_file("modelmux.pid");
                println!("✓ ModelMux stopped (PID: {})", pid);
                return;
            }
        }
    }

    // Try to find by port
    #[cfg(unix)]
    {
        let output = Command::new("lsof")
            .args(["-ti", ":8889"])
            .output();
        if let Ok(out) = output {
            let pid = String::from_utf8_lossy(&out.stdout).trim().to_string();
            if !pid.is_empty() {
                Command::new("kill")
                    .arg(&pid)
                    .status()
                    .ok();
                println!("✓ ModelMux stopped (PID: {})", pid);
                return;
            }
        }
    }

    println!("⚠ No running ModelMux instance found");
}

fn cmd_status() {
    #[cfg(unix)]
    {
        let output = Command::new("lsof")
            .args(["-ti", ":8889"])
            .output();

        if let Ok(out) = output {
            let pid = String::from_utf8_lossy(&out.stdout).trim().to_string();
            if !pid.is_empty() {
