fn cmd_chat(model: &str, system: &str) {
    println!("💬 Interactive Chat");
    println!("   Model: {}", model);
    println!("   Type 'quit' or 'exit' to stop\n");

    let client = reqwest::blocking::Client::new();
    let mut messages: Vec<serde_json::Value> = vec![
        serde_json::json!({"role": "system", "content": system}),
    ];

    loop {
        print!("{} ", colored::Colorize::green("You:"));
        use std::io::Write;
        std::io::stdout().flush().unwrap();

        let mut input = String::new();
        if std::io::stdin().read_line(&mut input).is_err() {
            break;
        }

        let input = input.trim();
        if input == "quit" || input == "exit" {
            println!("{} Goodbye!", colored::Colorize::yellow(""));
            break;
        }

        if input.is_empty() {
            continue;
        }

        messages.push(serde_json::json!({"role": "user", "content": input}));

        let response = client
            .post("http://localhost:8889/v1/chat/completions")
            .header("Content-Type", "application/json")
            .json(&serde_json::json!({
                "model": model,
                "messages": messages,
            }))
            .send();

        match response {
            Ok(resp) => {
                if let Ok(json) = resp.json::<serde_json::Value>() {
                    if let Some(content) = json
                        .get("choices")
                        .and_then(|c| c.as_array())
                        .and_then(|arr| arr.first())
                        .and_then(|c| c.get("message"))
                        .and_then(|m| m.get("content"))
                        .and_then(|c| c.as_str())
                    {
                        println!("{} {}", colored::Colorize::blue("Assistant:"), content);
                        println!();
                        messages.push(serde_json::json!({"role": "assistant", "content": content}));
                    } else {
                        println!("Error: No response");
                    }
                }
            }
            Err(e) => {
                eprintln!("Error: {}", e);
            }
        }
    }
}

